+import { createOpenRouter } from "@openrouter/ai-sdk-provider";
+import { generateObject } from "ai";
+import { NextResponse } from "next/server";
+import { z } from "zod";
+
+const feedbackSchema = z.object({
+  correct: z.boolean(),
+  exampleSentence: z.string(),
+  aiResponse: z.string(),
+  hint: z.string(),
+});
+
+const requestSchema = z.object({
+  task: z.string().optional(),
+  message: z.string().optional(),
+  data: z.record(z.string(), z.unknown()).optional(),
+});
+
+const definitionDataSchema = z.object({
+  word: z.string().min(1),
+  userDefinition: z.string().min(1),
+  correctDefinition: z.string().min(1),
+  exampleSentence: z.string().optional(),
+});
+
+const sentenceDataSchema = z.object({
+  word: z.string().min(1),
+  userSentence: z.string().min(1),
+  definition: z.string().min(1),
+  exampleSentence: z.string().optional(),
+  partOfSpeech: z.string().optional(),
+});
+
+const supportedTasks = new Set([
+  "validate-user-definition",
+  "validate-user-sentence",
+]);
+
+function badRequest(message: string) {
+  return NextResponse.json({ success: false, message }, { status: 400 });
+}
+
+function buildPrompt(task: string, data: z.infer<typeof requestSchema>["data"]) {
+  if (task === "validate-user-definition") {
+    const parsed = definitionDataSchema.parse(data);
+
+    return {
+      system:
+        "You are a concise vocabulary tutor. Judge whether the learner understands the target word. Return only structured feedback.",
+      prompt: `Target word: ${parsed.word}
+Correct definition: ${parsed.correctDefinition}
+Learner definition: ${parsed.userDefinition}
+Example sentence: ${parsed.exampleSentence || "No example provided."}
+
+Mark correct only if the learner's definition captures the main meaning. Be encouraging, specific, and brief.`,
+    };
+  }
+
+  const parsed = sentenceDataSchema.parse(data);
+
+  return {
+    system:
+      "You are a concise vocabulary tutor. Judge whether the learner used a vocabulary word correctly in an original sentence. Return only structured feedback.",
+    prompt: `Target word: ${parsed.word}
+Part of speech: ${parsed.partOfSpeech || "unknown"}
+Definition: ${parsed.definition}
+Learner sentence: ${parsed.userSentence}
+Reference example: ${parsed.exampleSentence || "No example provided."}
+
+Mark correct only if the sentence includes the target word and uses it in a way that fits the definition. Be encouraging, specific, and brief.`,
+  };
+}
+
+export async function POST(request: Request) {
+  let body: z.infer<typeof requestSchema>;
+
+  try {
+    body = requestSchema.parse(await request.json());
+  } catch {
+    return badRequest("Invalid JSON request body.");
+  }
+
+  if (!body.task) {
+    return badRequest("Missing task name.");
+  }
+
+  if (!supportedTasks.has(body.task)) {
+    return badRequest(
+      `Unsupported task "${body.task}". Supported tasks: ${Array.from(
+        supportedTasks
+      ).join(", ")}.`
+    );
+  }
+
+  if (!body.data) {
+    return badRequest("Missing task data.");
+  }
+
+  if (!process.env.OPENROUTER_KEY) {
+    return NextResponse.json(
+      {
+        success: false,
+        message: "AI feedback is not configured.",
+      },
+      { status: 503 }
+    );
+  }
+
+  let prompt: ReturnType<typeof buildPrompt>;
+
+  try {
+    prompt = buildPrompt(body.task, body.data);
+  } catch {
+    return badRequest("Invalid task data.");
+  }
+
+  try {
+    const openrouter = createOpenRouter({
+      apiKey: process.env.OPENROUTER_KEY,
+    });
+
+    const result = await generateObject({
+      model: openrouter(process.env.OPENROUTER_MODEL || "openai/gpt-4o-mini"),
+      schema: feedbackSchema,
+      schemaName: "VocabularyFeedback",
+      mode: "json",
+      temperature: 0.2,
+      system: prompt.system,
+      prompt: prompt.prompt,
+    });
+
+    return NextResponse.json({
+      success: true,
+      result: result.object,
+    });
+  } catch (error) {
+    console.error("Vocabulary feedback request failed:", error);
+
+    return NextResponse.json(
+      {
+        success: false,
+        message: "Unable to generate vocabulary feedback.",
+      },
+      { status: 502 }
+    );
+  }
+}
