+}
+
+interface VocabsFormASentencePracticeProps {
+  onBackToPracticeSelection?: () => void;
+}
+
+interface SentenceState {
+  currentQuestionIndex: number;
+  userSentence: string;
+  showResult: boolean;
+  score: number;
+  answeredQuestions: boolean[];
+  userAnswers: string[];
+  isSentenceComplete: boolean;
+  showUserSentences: { [key: number]: boolean };
+  questionStartTime: number;
+  restartKey: number;
+  isSubmitting: boolean;
+  feedbackByQuestion: { [key: number]: SentenceFeedback };
+}
+
+type SentenceAction =
+  | { type: "INITIALIZE_SENTENCE"; payload: { questionCount: number } }
+  | { type: "UPDATE_SENTENCE"; payload: string }
+  | { type: "START_SUBMISSION" }
+  | { type: "SUBMIT_SENTENCE"; payload: { feedback: SentenceFeedback } }
+  | { type: "NEXT_QUESTION" }
+  | { type: "PREVIOUS_QUESTION" }
+  | { type: "FINISH_SENTENCE" }
+  | { type: "RESTART_SENTENCE"; payload: { questionCount: number } }
+  | { type: "TOGGLE_USER_SENTENCES"; payload: number }
+  | { type: "SET_QUESTION_START_TIME"; payload: number }
+  | {
+      type: "LOAD_QUESTION_STATE";
+      payload: { userSentence: string; showResult: boolean };
+    };
+
+const initialSentenceState: SentenceState = {
+  currentQuestionIndex: 0,
+  userSentence: "",
+  showResult: false,
+  score: 0,
+  answeredQuestions: [],
+  userAnswers: [],
+  isSentenceComplete: false,
+  showUserSentences: {},
+  questionStartTime: Date.now(),
+  restartKey: 0,
+  isSubmitting: false,
+  feedbackByQuestion: {},
+};
+
+function sentenceReducer(
+  state: SentenceState,
+  action: SentenceAction
+): SentenceState {
+  switch (action.type) {
+    case "INITIALIZE_SENTENCE":
+      return {
+        ...state,
+        answeredQuestions: new Array(action.payload.questionCount).fill(false),
+        userAnswers: new Array(action.payload.questionCount).fill(""),
+        questionStartTime: Date.now(),
+        feedbackByQuestion: {},
+      };
+
+    case "UPDATE_SENTENCE":
+      return {
+        ...state,
+        userSentence: action.payload,
+      };
+
+    case "START_SUBMISSION":
+      return {
+        ...state,
+        isSubmitting: true,
+      };
+
+    case "SUBMIT_SENTENCE": {
+      const answeredQuestions = [...state.answeredQuestions];
+      const userAnswers = [...state.userAnswers];
+      const feedbackByQuestion = { ...state.feedbackByQuestion };
+
+      answeredQuestions[state.currentQuestionIndex] = true;
+      userAnswers[state.currentQuestionIndex] = state.userSentence;
+      feedbackByQuestion[state.currentQuestionIndex] = action.payload.feedback;
+
+      return {
+        ...state,
+        showResult: true,
+        isSubmitting: false,
+        score:
+          !state.answeredQuestions[state.currentQuestionIndex] &&
+          action.payload.feedback.correct
+            ? state.score + 1
+            : state.score,
+        answeredQuestions,
+        userAnswers,
+        feedbackByQuestion,
+      };
+    }
+
+    case "NEXT_QUESTION":
+      if (state.currentQuestionIndex + 1 >= state.answeredQuestions.length) {
+        return {
+          ...state,
+          isSentenceComplete: true,
+        };
+      }
+
+      return {
+        ...state,
+        currentQuestionIndex: state.currentQuestionIndex + 1,
+        questionStartTime: Date.now(),
+      };
+
+    case "PREVIOUS_QUESTION":
+      if (state.currentQuestionIndex === 0) return state;
+
+      return {
+        ...state,
+        currentQuestionIndex: state.currentQuestionIndex - 1,
+        questionStartTime: Date.now(),
+      };
+
+    case "FINISH_SENTENCE":
+      return {
+        ...state,
+        isSentenceComplete: true,
+      };
+
+    case "RESTART_SENTENCE":
+      return {
+        currentQuestionIndex: 0,
+        userSentence: "",
+        showResult: false,
+        score: 0,
+        answeredQuestions: new Array(action.payload.questionCount).fill(false),
+        userAnswers: new Array(action.payload.questionCount).fill(""),
+        isSentenceComplete: false,
+        showUserSentences: {},
+        questionStartTime: Date.now(),
+        restartKey: Date.now(),
+        isSubmitting: false,
+        feedbackByQuestion: {},
+      };
+
+    case "TOGGLE_USER_SENTENCES":
+      return {
+        ...state,
+        showUserSentences: {
+          ...state.showUserSentences,
+          [action.payload]: !state.showUserSentences[action.payload],
+        },
+      };
+
+    case "SET_QUESTION_START_TIME":
+      return {
+        ...state,
+        questionStartTime: action.payload,
+      };
+
+    case "LOAD_QUESTION_STATE":
+      return {
+        ...state,
+        userSentence: action.payload.userSentence,
+        showResult: action.payload.showResult,
+      };
+
+    default:
+      return state;
+  }
+}
+
+function calculateMasteryLevel(
+  correctAttempts: number,
+  totalAttempts: number,
+  consecutiveCorrect: number
+): WordPerformance["masteryLevel"] {
+  if (totalAttempts === 0) return "learning";
+
+  const accuracy = correctAttempts / totalAttempts;
+
+  if (accuracy >= 0.9 && consecutiveCorrect >= 3) return "mastered";
+  if (accuracy >= 0.7 && consecutiveCorrect >= 2) return "proficient";
+  if (accuracy >= 0.5) return "learning";
+  return "struggling";
+}
+
+function escapeRegex(value: string) {
+  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
+}
+
+function evaluateSentenceLocally(
+  sentence: string,
+  word: VocabularyWord
+): SentenceFeedback {
+  const trimmedSentence = sentence.trim();
+  const words = trimmedSentence.match(/[A-Za-z']+/g) || [];
+  const includesWord = new RegExp(`\\b${escapeRegex(word.word)}\\b`, "i").test(
+    trimmedSentence
+  );
+  const longEnough = words.length >= 6;
+  const notDefinitionOnly = !trimmedSentence
+    .toLowerCase()
+    .startsWith(`${word.word.toLowerCase()} means`);
+  const correct = includesWord && longEnough && notDefinitionOnly;
+
+  if (correct) {
+    return {
+      correct: true,
+      exampleSentence: word.example,
+      aiResponse:
+        "This sentence includes the vocabulary word and gives it enough context to be useful practice.",
+      hint: "",
+      source: "fallback",
+    };
+  }
+
+  const hint = !includesWord
+    ? `Use "${word.word}" in the sentence.`
+    : !longEnough
+    ? "Add more context so the meaning is clear."
+    : "Write an original sentence instead of only stating the definition.";
+
+  return {
+    correct: false,
+    exampleSentence: word.example,
+    aiResponse:
+      "I could not verify this as a strong vocabulary sentence with the basic local check.",
+    hint,
+    source: "fallback",
+  };
+}
+
+function prioritizeLearnedWords(
+  learnedWords: VocabularyWord[],
+  wordPerformance: PracticePerformanceData["wordPerformance"]
+) {
+  const categorizedWords = {
+    notPracticed: [] as VocabularyWord[],
+    struggling: [] as VocabularyWord[],
+    learning: [] as VocabularyWord[],
+    proficient: [] as VocabularyWord[],
+    mastered: [] as VocabularyWord[],
+  };
+
+  learnedWords.forEach((word) => {
+    const performance = wordPerformance[word.word];
+
+    if (!performance) {
+      categorizedWords.notPracticed.push(word);
+      return;
+    }
+
+    categorizedWords[performance.masteryLevel].push(word);
+  });
+
+  Object.keys(categorizedWords).forEach((key) => {
+    categorizedWords[key as keyof typeof categorizedWords].sort(
+      () => Math.random() - 0.5
+    );
+  });
+
+  return [
+    ...categorizedWords.notPracticed,
+    ...categorizedWords.struggling,
+    ...categorizedWords.learning,
+    ...categorizedWords.proficient,
+    ...categorizedWords.mastered,
+  ];
+}
