+const defaultProfile: UserProfileWithHistory = {
+  totalXP: 0,
+  level: 1,
+  questionsAnswered: 0,
+  correctAnswers: 0,
+  incorrectAnswers: 0,
+  answeredQuestionIds: [],
+  xpHistory: [],
+};
+
+function calculateLevel(totalXP: number) {
+  return Math.max(1, Math.floor(totalXP / 1000) + 1);
+}
+
+function saveUserProfile(profile: UserProfileWithHistory) {
+  if (typeof window !== "undefined") {
+    localStorage.setItem(USER_PROFILE_KEY, JSON.stringify(profile));
+  }
+
+  return profile;
+}
+
+export function getUserProfile(): UserProfileWithHistory {
+  if (typeof window === "undefined") return defaultProfile;
+
+  try {
+    const stored = localStorage.getItem(USER_PROFILE_KEY);
+    return stored ? { ...defaultProfile, ...JSON.parse(stored) } : defaultProfile;
+  } catch {
+    return defaultProfile;
+  }
+}
+
+export function addXPForCorrectAnswer(questionId: string, scoreBand = 1) {
+  const profile = getUserProfile();
+  const xpChange = Math.max(1, scoreBand) * 10;
+  const updatedProfile: UserProfileWithHistory = {
+    ...profile,
+    totalXP: profile.totalXP + xpChange,
+    questionsAnswered: profile.questionsAnswered + 1,
+    correctAnswers: profile.correctAnswers + 1,
+    answeredQuestionIds: [...profile.answeredQuestionIds, questionId],
+    xpHistory: [
+      ...profile.xpHistory,
+      { questionId, xpChange, timestamp: new Date().toISOString() },
+    ],
+  };
+
+  updatedProfile.level = calculateLevel(updatedProfile.totalXP);
+  return saveUserProfile(updatedProfile);
+}
+
+export function reduceXPForIncorrectAnswer(questionId: string, scoreBand = 1) {
+  const profile = getUserProfile();
+  const xpChange = -Math.floor((Math.max(1, scoreBand) * 10) / 2);
+  const updatedProfile: UserProfileWithHistory = {
+    ...profile,
+    totalXP: Math.max(0, profile.totalXP + xpChange),
+    questionsAnswered: profile.questionsAnswered + 1,
+    incorrectAnswers: profile.incorrectAnswers + 1,
+    answeredQuestionIds: [...profile.answeredQuestionIds, questionId],
+    xpHistory: [
+      ...profile.xpHistory,
+      { questionId, xpChange, timestamp: new Date().toISOString() },
+    ],
+  };
+
+  updatedProfile.level = calculateLevel(updatedProfile.totalXP);
+  return saveUserProfile(updatedProfile);
+}
